####________计算单细胞参数####
sc_meta <- function(sce.big){
  #计算线粒体比例
  sce.big[["percent.mt"]] <- PercentageFeatureSet(sce.big, pattern = "^MT-")
  
  #计算红细胞比例
  HB.genes <- c("HBA1","HBA2","HBB","HBD","HBE1","HBG1","HBG2","HBM","HBQ1","HBZ")
  HB_m <- match(HB.genes, rownames(sce.big@assays$RNA)) 
  HB.genes <- rownames(sce.big@assays$RNA)[HB_m] 
  HB.genes <- HB.genes[!is.na(HB.genes)] 
  sce.big[["percent.HB"]] <- PercentageFeatureSet(sce.big, features=HB.genes) 
  
  #计算核糖体比例
  rb.genes <- rownames(sce.big)[grep("^RP[SL]",rownames(sce.big))]
  pbmc_assay <- GetAssayData(object = sce.big, slot = "counts")
  percent.ribo <- colSums(pbmc_assay[rb.genes,])/Matrix::colSums(pbmc_assay)*100
  sce.big <- AddMetaData(sce.big, percent.ribo, col.name = "percent.ribo")
  
  col.num <- length(levels(as.factor(sce.big@meta.data$orig.ident)))
  
  #每个细胞的每个UMI的基因数量
  sce.big$log10GenesPerUMI <- log10(sce.big$nFeature_RNA) / log10(sce.big$nCount_RNA)
  return(sce.big)
  
}
