####________读取亚聚类命名与坐标####
for (i in 2:length(cells)) {
  scRNA_sub_new <- readRDS(paste0(dir_data,"\\",cells[i],"_subcluster.rds"))
  meta <- scRNA_sub_new@meta.data
  meta$Cells_raw <- str_split_fixed(rownames(meta),"_",2)[,2]
  
  meta$Cells <- paste0(meta$sample,"_",meta$Cells_raw)
  metaa <- meta[,c("Cells","cluster")]
  metaa$cellname <- cells[i]
  sub_meta <- rbind(sub_meta,metaa)
  print(paste0("i=",i,":",cells[i]))
}


