####_____ggplot绘制umap####
library(Seurat)
library(tidyverse)
library(ggrepel)

umap = scRNA@reductions$umap@cell.embeddings %>%  #坐标信息
  as.data.frame() %>% 
  cbind(cell_type = scRNA@meta.data$cell_type,
        cluster = scRNA@meta.data$cluster,
        Group = scRNA@meta.data$Group,
        Sample = scRNA@meta.data$Sample,
        Gender = scRNA@meta.data$Gender,
        Age = scRNA@meta.data$Age,
        phase = scRNA@meta.data$phase) # 注释后的label信息 ，改为cell_type

cell_type_med <- umap %>%
  group_by(cell_type) %>%
  summarise(
    UMAP_1 = median(UMAP_1),
    UMAP_2 = median(UMAP_2)
  )

####_______cell_type####

ggplot(umap,aes(x= UMAP_1, y = UMAP_2 ,color = cell_type)) +  
  geom_point(size = 0.0001 , alpha =1 )  + 
  scale_color_manual(values = color_cell)+
  theme(panel.grid.major = element_blank(), #主网格线
        panel.grid.minor = element_blank(), #次网格线
        panel.border = element_blank(), #边框
        axis.title = element_blank(),  #轴标题
        axis.text = element_blank(), # 文本
        axis.ticks = element_blank(),
        panel.background = element_rect(fill = 'white'), #背景色
        plot.background=element_rect(fill="white")
  )+
  theme(legend.position = "none") +
  geom_label_repel(aes(label=cell_type),data = cell_type_med,point.padding=unit(0.5,"lines"))

