options(download.file.method = "wininet")
# devtools::install_github("TheHumphreysLab/plot1cell")
# ## or the development version, devtools::install_github("HaojiaWu/plot1cell")
# 
# ## You might need to install the dependencies below if they are not available in your R library.
# bioc.packages <- c("biomaRt","GenomeInfoDb","EnsDb.Hsapiens.v86","GEOquery","simplifyEnrichment","ComplexHeatmap")
# bioc.packages <- c("EnsDb.Hsapiens.v86","GEOquery")
# BiocManager::install(bioc.packages)
# 
# dev.packages <- c("chris-mcginnis-ucsf/DoubletFinder","hhoeflin/hdf5r","mojaveazure/loomR")
# devtools::install_github(dev.packages)

library(plot1cell)


cells_order <- c("Mast",'Neut',"B","T_NK","Mo","Macro","DC","EC","Fib","SMC")
color_cell_order <- c('Mast' = "#b6b800",
                      'Neut' = '#FF8AB6',
                      'B' = "#ff1f1d",
                      'T_NK' = "#a763ac",
                      'Mo' = "#01c1cc",
                      'Macro' = "#b45b5d",
                      'DC' = "#85d5f8",
                      'EC' = "#00a23f",
                      'Fib' = '#ff7f00',
                      'SMC' = '#0067aa'
)

###准备圈图数据
circ_data <- prepare_circlize_data(scRNA, scale = 0.7)
circ_data$Cluster <- factor(circ_data$Cluster,levels = cells_order)
circ_data$Age <- factor(circ_data$Age,levels = c("26","27","39","45","46","49","50","51","53","58","63","73"))
set.seed(1234)
# 设置细胞分群信息的颜色
rep_colors<-rand_color(length(names(table(scRNA$Sample))))


###plot and save figures
# 绘制细胞分群圈图
pdf('1_All_circlize_plot_circle_wai.pdf', width = 5, height = 5)
plot_circlize(circ_data,do.label = TRUE, pt.size = 0.01, col.use = color_cell_order ,bg.color = 'white', kde2d.n = 100, repel = FALSE, label.cex = 0.6)
# 添加细胞群注释信息
add_track(circ_data, group = "Group", colors = color_group, track_num = 2) ## 可以将其更改为您的metada中的一列
add_track(circ_data, group = "Gender", colors = color_sex, track_num = 3)
add_track(circ_data, group = "Age", colors = my36colors, track_num = 4)
dev.off()

pdf('1_All_circlize_plot_legend.pdf', width = 5, height = 5)
plot.new()
legend("topleft", 
       legend = c('naCTL','AD','nCTL_B','AD_B'),
       col = color_group,
       pch = 15,
       cex=1,
       pt.cex=1.5,
       box.lwd = 0,
       bg=NULL,
       y.intersp = 1,
       box.lty=0)
legend("bottomleft", 
       legend = c('Female','Male'),
       col = color_sex,
       pch = 15,
       cex=1,
       pt.cex=1.5,
       box.lwd = 0,
       bg=NULL,
       y.intersp = 1,
       box.lty=0)
legend("bottomright", 
       legend = c("26","27","39","45","46","49","50","51","53","58","63","73"),
       col = my36colors,
       pch = 15,
       cex=1,
       pt.cex=1.5,
       box.lwd = 0,
       bg=NULL,
       y.intersp = 1,
       box.lty=0)
dev.off()


###plot and save figures
# 绘制细胞分群圈图
pdf('1_All_circlize_plot.pdf', width = 8, height = 8)
plot_circlize(circ_data,do.label = TRUE, pt.size = 0.01, col.use = color_cell_order ,bg.color = 'white', kde2d.n = 20000, repel = FALSE, label.cex = 0.6)
# 添加细胞群注释信息
add_track(circ_data, group = "Group", colors = color_group, track_num = 2) ## 可以将其更改为您的metada中的一列
add_track(circ_data, group = "Gender", colors = color_sex, track_num = 3)
add_track(circ_data, group = "Age", colors = my36colors, track_num = 4)
