#读取细胞类型marker
cellmaker_all <- read.csv('3_cell_type_marker_noRBMT.csv')
cellmaker_all[which(cellmaker_all$cluster == "T_NK"),6] <- "TNK"


for (i in 1:length(cells)) {
  markers <- intersect(
    cellmaker_all[which(cellmaker_all$cluster == cells[i] & cellmaker_all$avg_log2FC > 0),"gene"],
    all_markers_group[which(all_markers_group$cell_type == cells[i]),"gene"])
  
  group_marker <- all_markers_group %>% 
    dplyr::filter(gene %in% markers) %>%
    dplyr::filter(cell_type == cells[i]) %>%
    distinct(gene,.keep_all = T) %>% 
    arrange(group)
  
  top_group_marker <- group_marker %>%
    group_by(group)  %>%
    top_n(2,avg_log2FC)
  if(i==1){
    all_group_marker <- top_group_marker
  }else{
    all_group_marker <- rbind(all_group_marker,top_group_marker)
  }
  
  
  
}
table(all_group_marker$cell_type,all_group_marker$group)
