####____[2]分细胞类型####
ids=bitr(marker_noRiobo_noMT$gene,'SYMBOL','ENTREZID','org.Hs.eg.db') ## 将SYMBOL转成ENTREZID
marker_noRiobo_noMT=merge(marker_noRiobo_noMT,ids,by.x='gene',by.y='SYMBOL')




#每种细胞类型的marker做功能富集然后合并富集结果
for(i in 1:length(cells)){
  cell <- cells[i]
  marker <- subset(marker_noRiobo_noMT,cluster == cell)
  ego <- enrichGO(gene = marker$gene,
                  OrgDb ='org.Hs.eg.db',
                  keyType = "SYMBOL",
                  ont = 'BP',#设置为ALL时BP,cC,MF都计算
                  pAdjustMethod = "BH",
                  pvalueCutoff = 0.01,
                  qvalueCutoff = 0.05)
  ego <- as.data.frame(ego)
  ego$cell_type <- cell
  
  ekegg <- enrichKEGG(gene = marker$ENTREZID,
                      universe = ,
                      organism = "hsa",
                      keyType = "kegg",
                      pAdjustMethod = "BH",
                      pvalueCutoff = 0.01,
                      qvalueCutoff = 0.05)
  ekegg <- as.data.frame(ekegg)
  ekegg$cell_type <- cell
  
  
  if(i==1){
    result_go <- ego
    result_kegg <- ekegg
  }else{
    result_go <- rbind(result_go,ego)
    result_kegg <- rbind(result_kegg,ekegg)
  }
  
  
  print(cell)
}
result_go$cell_type <- factor(result_go$cell_type,levels = cells)
result_kegg$cell_type <- factor(result_kegg$cell_type,levels = cells)
result_go$logp <- -log10(result_go$pvalue)
result_kegg$logp <- -log10(result_kegg$pvalue)

#将分数字符转化为小数
result_go <- result_go %>% 
  separate(GeneRatio,c("gene_in","gene_back"),"/") %>%
  mutate(GeneRatio = as.numeric(gene_in)/as.numeric(gene_back))
result_kegg <- result_kegg %>% 
  separate(GeneRatio,c("gene_in","gene_back"),"/") %>%
  mutate(GeneRatio = as.numeric(gene_in)/as.numeric(gene_back))

write.csv(result_go,"5_enrichGO.csv",row.names = F)
write.csv(result_kegg,"5_enrichKEGG.csv",row.names = F)


#获取展示的通路
result_go_sub <- result_go %>%
  group_by(cell_type)  %>% top_n(n = 2,wt = logp)
result_kegg_sub <- result_kegg %>%
  group_by(cell_type)  %>% top_n(n = 2,wt = logp)



