####____[3]各细胞类型圈图####
color <- c('#A5D8DC','#EB999C','#C1C8DD','#99CC99','#CCE0F5','#C9E1BD','#EFE378')

library(GOplot)

for (i in 5:length(cells)) {
  cell <- cells[i]
  marker <- marker_noRiobo_noMT[which(marker_noRiobo_noMT$cluster == cell),]
  marker_unique <- marker[!duplicated(marker$gene),]
  genelist <- data.frame(ID = marker_unique$gene, logFC = marker_unique$avg_log2FC)
  row.names(genelist)=genelist[,1]
  
  ####______GOBP####
  result_go_cell <- result_go[which(result_go$cell_type == cell),]
  result_go_cell$Category <- "GO_BP"
  
  go = data.frame(Category = result_go_cell$Category,ID = result_go_cell$ID,Term = result_go_cell$Description, Genes = gsub("/", ", ", result_go_cell$geneID), adj_pval = result_go_cell$p.adjust,logp = result_go_cell$logp)
  go <- go[order(go$logp,decreasing = T),]
  
  #读取基因的logFC文件
  circ <- circle_dat(go,genelist)
  if(nrow(go) >= 5){#限定term数目
    termNum =5
  }else{
    termNum =nrow(go)
  }
  
  geneNum = nrow(genelist)                        #限定基因数目
  chord <- chord_dat(circ, genelist[1:geneNum,], go$Term[1:termNum])
  
  
  
  p1 <- GOCluster(circ.gsym, 
                  go$Term[1:termNum], 
                  lfc.space = 0.2,                   #倍数跟树间的空隙大小
                  lfc.width = 0.2,
                  lfc.col = c("white","red"),
                  clust.by = 'logFC',#变化倍数的圆圈宽度
                  term.col = color[1:termNum],     #自定义term的颜色
                  term.space = 0.2,                  #倍数跟term间的空隙大小
                  term.width = 1)                    #富集term的圆圈宽度
  ggsave(paste0("5_each_",cell,"_GO_top",termNum,"_circos.pdf"),plot = p1,width = 40,height = 10)
  
  ####______KEGG####
  genelist <- data.frame(ID = marker_unique$ENTREZID, logFC = marker_unique$avg_log2FC)
  row.names(genelist)=genelist[,1]
  
  result_kegg_cell <- result_kegg[which(result_kegg$cell_type == cell),]
  result_kegg_cell$Category <- "KEGG"
  
  kegg = data.frame(Category = result_kegg_cell$Category,ID = result_kegg_cell$ID,Term = result_kegg_cell$Description, Genes = gsub("/", ", ", result_kegg_cell$geneID), adj_pval = result_kegg_cell$p.adjust,logp = result_kegg_cell$logp)
  kegg <- kegg[order(kegg$logp,decreasing = T),]
  
  #读取基因的logFC文件
  circ <- circle_dat(kegg,genelist)
  if(nrow(kegg) >= 5){#限定term数目
    termNum =5
  }else{
    termNum =nrow(kegg)
  }
  #限定term数目
  geneNum = nrow(genelist)                        #限定基因数目
  chord <- chord_dat(circ, genelist[1:geneNum,], kegg$Term[1:termNum])
  
  
  
  p2 <- GOCluster(circ.gsym, 
                  kegg$Term[1:termNum], 
                  lfc.space = 0.2,                   #倍数跟树间的空隙大小
                  lfc.width = 0.2,
                  lfc.col = c("white","red"),
                  clust.by = 'logFC',#变化倍数的圆圈宽度
                  term.col = color[1:termNum],     #自定义term的颜色
                  term.space = 0.2,                  #倍数跟term间的空隙大小
                  term.width = 1)                    #富集term的圆圈宽度
  ggsave(paste0("5_each_",cell,"_KEGG_top",termNum,"_circos.pdf"),p2,width = 40,height = 10)
  print(cell)
}



