####__________C7ST#####
sample <- 'C7ST'
cell_num <- data.frame(cell_type = c("SMC","Fib","EC","B","T_NK","Macro","Mast","Mo","DC","Neut"),
                       cellratio = c(0.426101889,0.091814539,0.179851173,0.010990269,0.009273039,0.249570693,0.009044076,0.009387521,0.0139668,0)                      
)
cell_num$cell_type <- factor(cell_num$cell_type,levels = c("EC","SMC","Fib","Macro","Mo","DC","Mast","B","T_NK","Neut"))
ggplot(cell_num,aes(cell_type,cellratio))+
  geom_bar(aes(fill=cell_type),stat="identity", width = 0.5, )+
  scale_fill_manual(values = color_cell)+
  theme(legend.position = "none",
        axis.line = element_line(colour="white"),
        axis.ticks = element_line(colour="white"),
        panel.grid.major = element_blank(), panel.grid.minor = element_blank(),
        panel.background = element_rect(fill = 'black', color = 'black'), # 设置背景为黑色
        plot.background = element_rect(fill = 'black', color = 'black'), # 设置图表背景为黑色
        text = element_text(color = 'white') # 设置字体颜色为白色
  )+
  coord_fixed(ratio = 20)
ggsave(paste0("1_",sample,"_cellratio_bar.pdf"),width = 3.5,height = 3.5)



