####______[1]C7ST#####
sample <- "C7ST"

spatial_count <- Read10X(paste0(dir_sample,"\\",sample,"\\filtered_feature_bc_matrix"))
spatial_location <- Read10X_Image(image.dir = paste0(dir_sample,"\\",sample,"\\spatial\\"))
spatial_location <- spatial_location@coordinates[,c(4,5)]
colnames(spatial_location) <- c("x", "y")
# 向右旋转180度
spatial_location[,2] <- spatial_location[,2]
spatial_location[,1] <- -spatial_location[,1]
colnames(spatial_location) <- c("x", "y")
spatial_location <- spatial_location[colnames(spatial_count),]

ggplot(spatial_location,aes(x,y))+geom_point()
spatial_location <- spatial_location[colnames(spatial_count),]


CARD_obj = createCARDObject(
  sc_count = sc_count,
  sc_meta = sc_meta,
  spatial_count = spatial_count,
  spatial_location = spatial_location,
  ct.varname = "cellType",
  ct.select = unique(sc_meta$cellType),
  sample.varname = "sampleInfo",
  minCountGene = 100,
  minCountSpot = 5) 
CARD_obj = CARD_deconvolution(CARD_object = CARD_obj)

####___________细胞类型比例密度####
#展示感兴趣的细胞类型
ct.visualize = c("SMC","Fib","EC","Macro")
range(spatial_location$x)#-10965  -1161
range(spatial_location$y)#10464  2562
## visualize the spatial distribution of the cell type proportion
CARD.visualize.prop(
  proportion = CARD_obj@Proportion_CARD,        
  spatial_location = CARD_obj@spatial_location, 
  ct.visualize = ct.visualize,                 ### 选择要可视化的细胞类型
  colors = color_cellprop, ###可以手动设置颜色
  NumCols = 2,    ###图中展示的细胞类型的列数
  pointSize = 1)   +
  theme(panel.background = element_rect(fill = "white"),
        panel.grid=element_blank(),
        axis.text.x = element_blank(),
        axis.ticks.x = element_blank(),
        axis.text.y = element_blank(),
        axis.ticks.y = element_blank())+
  xlab("")+ ylab("")+xlim(-11000,-1000)+ylim(2000,11000)+
  theme(panel.background = element_rect(fill = "black"), panel.grid=element_blank())+
    coord_equal()
ggsave("1_spot_C7ST_cellprop.pdf",width = 8,height = 8)

####___________特征基因表达####
CARD.visualize.gene(
  spatial_expression = CARD_obj@spatial_countMat,
  spatial_location = CARD_obj@spatial_location,
  gene.visualize = c("TAGLN","DCN","VWF","CD14"),
  colors = NULL,
  NumCols = 4)+
  theme(panel.background = element_rect(fill = "white"),
        panel.grid=element_blank(),
        axis.text.x = element_blank(),
        axis.ticks.x = element_blank(),
        axis.text.y = element_blank(),
        axis.ticks.y = element_blank())+
  xlab("")+ ylab("")+xlim(-11000,-1000)+ylim(-11000,-2000)+
  theme(panel.background = element_rect(fill = "black"), panel.grid=element_blank())+
  coord_equal()
ggsave(paste0("2_spot_",sample,'_marker.pdf'),width = 32,height = 9)

