hebing2_features<-cbind(hebing2,features_exp)
colnames(hebing2_features)[4] <- "gene"

ggplot()+
  geom_point(data=hebing, mapping=aes(x = coord_x,y = coord_y),shape = 21, colour = "#2C1733", fill = "#2C1733", size = 2)+
  
  geom_point(data=hebing2_features, mapping=aes(x = -coord_y,y = -coord_x,fill = gene),shape = 21,  size = 2,alpha = 0.7)+
