        axis.ticks.x = element_blank(),
        axis.text.y = element_blank(),
        axis.ticks.y = element_blank(),
        legend.position = "top")+
  xlab("")+ ylab("")+
  theme(panel.background = element_rect(fill = "black"), panel.grid=element_blank())+
