hebing2_1<-hebing2[which(hebing2$subidents %in% "MonocyteDerivedMacrophage"),]
hebing2_1<-hebing2_1[,c(2,3)]
hebing2_2<-hebing2[which(hebing2$subidents %in% "ProliferatingM2"),]
hebing2_2<-hebing2_2[,c(2,3)]
hebing2_3<-hebing2[which(hebing2$subidents %in% "M1Macrophages_1"),]
hebing2_3<-hebing2_3[,c(2,3)]
hebing2_4<-hebing2[which(hebing2$subidents %in% "M1Macrophages_2"),]
hebing2_4<-hebing2_4[,c(2,3)]
hebing2_5<-hebing2[which(hebing2$subidents %in% "M2Macrophages_1"),]
hebing2_5<-hebing2_5[,c(2,3)]
hebing2_6<-hebing2[which(hebing2$subidents %in% "M2Macrophages_2"),]
hebing2_6<-hebing2_6[,c(2,3)]


ggplot()+
  geom_point(data=hebing, mapping=aes(x = coord_x,y = coord_y),shape = 21, colour = "#2C1733", fill = "#2C1733", size = 1, stroke = 1.5)+
  geom_point(data=hebing2_1, mapping=aes(x = -coord_y,y = -coord_x),shape = 21, colour = "#0067aa", fill = "#0067aa", size = 0.1, stroke = 1.5,alpha = 4/5)+
  geom_point(data=hebing2_2, mapping=aes(x = -coord_y,y = -coord_x),shape = 21, colour = "#ff7f00", fill = "#ff7f00", size = 0.1, stroke = 1.5,alpha = 4/5)+
  geom_point(data=hebing2_3,mapping=aes(x = -coord_y,y = -coord_x),shape = 21, colour = "#00a23f", fill = "#00a23f", size = 0.1, stroke = 1.5,alpha = 4/5)+
  geom_point(data=hebing2_4, mapping=aes(x = -coord_y,y = -coord_x),shape = 21, colour = "#ff1f1d", fill = "#ff1f1d", size = 0.1, stroke = 1.5,alpha = 4/5)+
  geom_point(data=hebing2_5, mapping=aes(x = -coord_y,y = -coord_x),shape = 21, colour = "#a763ac", fill = "#a763ac", size = 0.1, stroke = 1.5,alpha = 4/5)+
  geom_point(data=hebing2_6, mapping=aes(x = -coord_y,y = -coord_x),shape = 21, colour = "#b45b5d", fill = "#b45b5d", size = 0.1, stroke = 1.5,alpha = 4/5)+
  
  theme(panel.background = element_rect(fill = "white"),
        panel.grid=element_blank(),
        axis.text.x = element_blank(),
        axis.ticks.x = element_blank(),
        axis.text.y = element_blank(),
        axis.ticks.y = element_blank(),
        title = element_text(size = 12))+
  xlab("")+ ylab("")+
  theme(panel.background = element_rect(fill = "black"), panel.grid=element_blank())+
  coord_equal(ratio = 1.2)+
  ggtitle("Merged")
