metadata <- as.data.frame(scRNA_sub@meta.data)
component <- as.data.frame(t(cds@reducedDimS))
colnames(component)=c("component1","component2")

pData(cds)$umap_2 <- umap$UMAP_2
pData(cds)$umap_1 <- umap$UMAP_1
pData(cds)$component1 <- component$component1
pData(cds)$component2 <- component$component2
pData(cds)$Contraction <- metadata$Contraction1
pData(cds)$Synthesis <- metadata$Synthesis1
pData(cds)$Inflammatory <- metadata$Inflammatory1
pData(cds)$Apoptosis <- metadata$Apoptosis1
pData(cds)$Angiogenesis <- metadata$Angiogenesis1

data <- as.data.frame(pData(cds))




####_________查找monocle选择的高变基因####
disp_table <- dispersionTable(cds)#调用estimateDispersions计算一个平滑函数，描述每个基因在细胞中表达的方差如何根据平均值变化。

disp.genes <- subset(disp_table, mean_expression >= 0.5&dispersion_empirical >= 1*dispersion_fit)

disp.genes <- as.character(disp.genes$gene_id)
diff_test <- differentialGeneTest(cds[disp.genes,], cores = 4, 
                                  fullModelFormulaStr = "~sm.ns(Pseudotime)")#测试每个基因的差异表达作为伪时间的函数或根据指定的其他协变量。
sig_gene_names <- row.names(subset(diff_test, qval < 1e-04))#以qval为指标，挑选显著
write.table(diff_test,"7_highvariant_gene_monocle.txt",sep = "\t",col.names = T,row.names = T)

diff_test <- read.table("7_highvariant_gene_monocle.txt",sep = "\t",header = T,check.names = F,stringsAsFactors = F,row.names = 1)

plot_cell_trajectory(cds, color_by="Pseudotime", size=1,show_backbone = TRUE)


####_________1. 绘制轨迹图######

####____________提取轨迹######
reduced_dim_coords <- reducedDimK(cds)
ica_space_df <- Matrix::t(reduced_dim_coords) %>%
  as.data.frame() %>%
  select_(prin_graph_dim_1 = 1, prin_graph_dim_2 = 2) %>%
  mutate(sample_name = rownames(.), sample_state = rownames(.))
dp_mst <- minSpanningTree(cds)
edge_df <- dp_mst %>%
  igraph::as_data_frame() %>%
  select_(source = "from", target = "to") %>%
  left_join(ica_space_df %>% select_(source="sample_name", source_prin_graph_dim_1="prin_graph_dim_1", source_prin_graph_dim_2="prin_graph_dim_2"), by = "source") %>%
  left_join(ica_space_df %>% select_(target="sample_name", target_prin_graph_dim_1="prin_graph_dim_1", target_prin_graph_dim_2="prin_graph_dim_2"), by = "target")


