#devtools::install_github("theislab/destiny")
library(destiny) # 加载 destiny...
library(Biobase)
library(grid)
library(rgl)

raw_data <- as.matrix(GetAssayData(scRNA_sub))
anno_mat <- scRNA_sub@meta.data
set <- ExpressionSet(raw_data, phenoData=AnnotatedDataFrame(anno_mat))
dmap <- DiffusionMap(set)

plot(dmap,col_by="cluster",pch=20,dcs = c(1,2,3))
#可视化
#install.packages("rgl")
#MoDeMacro  M1Macro   M2Macro LCAMacro OPMacro M1Macro  ProMacro
#'#0067AA','#00A23F','#A763AC','#B45B5D','#FF1F1D','#FF7F00'
plot3d(eigenvectors(dmap)[, 1:3],
       col = dmap@data_env[["data"]]@phenoData@data[["cluster_colors"]],
       type = 'p', radius = 0.001)

#view3d(theta = 10, phi = 30, zoom = .8)
#选起始点
cor<-eigenvectors(dmap)[,1:3]
#Idents(scRNA_sub)<-scRNA_sub$idents
scRNA_sub_start <- subset(scRNA_sub,idents ="ConSMC" )
#cor<-cor[order(cor[,1]),]
cor_V<-cor[colnames(scRNA_sub_start),]

cor_V_s <- cor_V[which(cor_V[,1] > -0.015 & cor_V[,1] < -0.01 & cor_V[,2] < -0.02  &  cor_V[,3] > 0.02),]

#绘图
pdf(file = "7_DC_plot.pdf",width = 10,height = 10)
plot.DiffusionMap(dmap, dims=c(1,-3,-2),col_by = "cluster",pch = 20,pal = c("#00a23f","#0067aa","#ff7f00","#ff1f1d","#a763ac",'#B45B5D'))
dev.off()


#选择根节点创建伪时间排序并将单元格分配给三个分支之一
dpt <- DPT(dmap,tips = which(colnames(set) == "A1C_CACTTCAGACCTACAAGGGGCGGATAA"))

plot(dpt,root = 2, paths_to = c(-1,-3,-2),col_by = 'branch')

pdf(file = "7_DC_plot_pseudotime.pdf",width = 10,height = 10)
plot(dpt,dcs = c(1,-3,-2), pch = 20)
dev.off()

save(dmap,file = "7_DC_dmap.RData")
#load(file = "7_DC_dmap.RData")
save(dpt,file = "7_DC_dpt.RData")
