                                   rep("pro_fibrotic",length(pro_fibrotic)),
                                   rep("PU_1",length(PU_1)),
                                   rep("SMAD3",length(SMAD3)),
                                   rep("F_actin",length(F_actin)),
                                   rep("aSMA",length(aSMA))),
                         features.plot = markers)

#获取Seurat气泡图的绘图数据
