ECM_gene <- read.table("D:\\1ISSUE\\主动脉夹层动脉瘤\\0_主动脉夹层测序数据\\自己\\3_subcluster\\ECM.txt",sep = "\t",header = T,check.names = F,stringsAsFactors = F)
