}




####________irGSEA####
options(download.file.method = "wininet")
devtools::install_github("chuiqin/irGSEA", force =T)


#加载R包
library(Seurat)
library(RcppML)
library(irGSEA)
scRNA_sub <- irGSEA.score(object = scRNA_sub,assay = "RNA", 
                             slot = "data", seeds = 123, ncores = 1,
                             min.cells = 10, min.feature = 10,
                             custom = T, msigdb = F, geneset = ECM_gene_list, 
                             method = c("AUCell","UCell","ssgsea"),
                             aucell.MaxRank = NULL, ucell.MaxRank = NULL, 
                             kcdf = 'Gaussian')
Assays(ECM_score)

ECM_dge <- irGSEA.integrate(object = scRNA_sub,
                               group.by = "cluster",
                               method = c("AUCell","UCell","ssgsea"))
# 查看RRA识别的在多种打分方法中都普遍认可的差异基因集
geneset.show <- ECM_dge$RRA %>% 
  dplyr::filter(pvalue <= 0.05) %>% 
  dplyr::pull(Name) %>% unique(.)
irGSEA.heatmap.plot <- irGSEA.heatmap(object = ECM_dge,
                                      method = "RRA",
                                      top = 50,
                                      show.geneset = NULL)
irGSEA.heatmap.plot

p1 <- irGSEA.heatmap(object = ECM_dge,
               method = "AUCell",
               top = 50,
               show.geneset = NULL)
p2 <- irGSEA.heatmap(object = ECM_dge,
               method = "UCell",
               top = 50,
               show.geneset = NULL)
p3 <- irGSEA.heatmap(object = ECM_dge,
               method = "singscore",
               top = 50,
               show.geneset = NULL)
p4 <- irGSEA.heatmap(object = ECM_dge,
               method = "ssgsea",
               top = 50,
               show.geneset = NULL)
p5 <- irGSEA.heatmap(object = ECM_dge,
               method = "JASMINE",
               top = 50,
               show.geneset = NULL)
p6 <- irGSEA.heatmap(object = ECM_dge,
               method = "viper",
               top = 50,
               show.geneset = NULL)
(p1+p2+p3)/(p4+p5+p6)


irGSEA.vlnplot(object = scRNA_sub,
               method = c("AUCell","UCell","ssgsea"),
               show.geneset = "ECM-remodeling")

irGSEA.ridgeplot(object = scRNA_sub,
                 method = "UCell",
                 show.geneset = "ECM-remodeling")

