####____[6]特定亚群间差异基因#######
scRNA_sub[["RNA"]]@counts<-as.matrix(scRNA_sub[["RNA"]]@counts)+1

#阈值确定：
pvalue = 0.05
log2FC = 1

de_13 <- FindMarkers(scRNA_sub,ident.1  = "Fibroblasts_3",ident.2 = "Fibroblasts_1",test.use = 'wilcox',min.pct = 0.25,verbose = T)
de_13$gene <- rownames(de_13)

#根据阈值添加上下调分组标签：
de_13$DE <- case_when(
  de_13$avg_log2FC > log2FC & de_13$p_val < pvalue ~ "Fibroblasts_3",
  de_13$avg_log2FC < -log2FC & de_13$p_val < pvalue ~ "Fibroblasts_1",
  TRUE ~ 'none'
)
#转换为因子，指定绘图顺序；
de_13$'-log10(pvalue)' <- -log10(de_13$p_val) #新增-log10p列
de_13[which(de_13$`-log10(pvalue)` > 323.3062),'-log10(pvalue)'] <- 306 #305.6064305.6064
de_13$DE <- factor(de_13$DE, levels = c("Fibroblasts_3","Fibroblasts_1","none"))

write.table(de_13,"5_DE_gene_13.txt",sep = "\t",row.names = F,col.names = T,quote = F)

de_23 <- FindMarkers(scRNA_sub,ident.1  = "Fibroblasts_3",ident.2 = "Fibroblasts_2",test.use = 'wilcox',min.pct = 0.25,verbose = T)
de_23$gene <- rownames(de_23)

#根据阈值添加上下调分组标签：
de_23$DE <- case_when(
  de_23$avg_log2FC > log2FC & de_23$p_val < pvalue ~ "Fibroblasts_3",
  de_23$avg_log2FC < -log2FC & de_23$p_val < pvalue ~ "Fibroblasts_2",
  TRUE ~ 'none'
)

#转换为因子，指定绘图顺序；
de_23$'-log10(pvalue)' <- -log10(de_23$p_val) #新增-log10p列
de_23[which(de_23$`-log10(pvalue)` > 307.0190),'-log10(pvalue)'] <- 308 #305.6064305.6064
de_23$DE <- factor(de_23$DE, levels = c("Fibroblasts_3","Fibroblasts_2","none"))

write.table(de_23,"6_DE_gene_23.txt",sep = "\t",row.names = F,col.names = T,quote = F)



####_________火山图####

de_13 <- read.table("6_DE_gene_13.txt",sep = "\t",header = T,check.names = F,stringsAsFactors = F)
de_23 <- read.table("6_DE_gene_23.txt",sep = "\t",header = T,check.names = F,stringsAsFactors = F)


de_13_sig <- de_13[which(de_13$p_val < 0.05 & abs(de_13$avg_log2FC) > 1),]
de_23_sig <- de_23[which(de_23$p_val < 0.05 & abs(de_23$avg_log2FC) > 1),]



color_raw <- c('#0067aa',"#ff7f00",'#00a23f',"#ff1f1d","#a763ac","#b45b5d","#b6b800","#01c1cc","#85d5f8",'#FF8AB6')
#自定义颜色：
mycol <- c("#ff1f1d","#ff7f00","#d8d8d8")

library(ggrepel)
diff12 <- de_13 %>%
  mutate(Difference = pct.1 - pct.2) 


ggplot(diff12, aes(x=Difference, y=avg_log2FC, color = DE)) + 
  geom_point(size=0.8,alpha = 0.8) + 
  scale_color_manual(values=mycol) +
  geom_text_repel(data = subset(diff12,gene %in% intersect(unique(ECM_gene$gene_name),de_13_sig$gene)),
                  aes(label = gene),
                  color="black", #设置label中标签的颜色
                  segment.colour = "black",#设置label框的颜色
                  label.padding = 0.1,
                  max.overlaps = 200,
                  segment.size = 0,  #框的大小
                  size=3)+
  ggtitle("") +
  geom_vline(xintercept = 0.0,linetype=2)+
  
  geom_hline(yintercept = -1,linetype=2)+
  geom_hline(yintercept = 1,linetype=2)+
  theme_classic(base_size = 12)#改变图例大小
ggsave("6_DE_ECM_gene_volcano_13.pdf",width = 5,height = 3.8)

mycol <- c("#ff1f1d","#00a23f","#d8d8d8")

