development <- c('JUNB','EGR1','SOX17','ACE')#31146585,vascular development genes,细胞发育和分化的关键调控因子
antigen_presentation <- c("HLA-DMA","HLA-DPA1","HLA-DPB1","HLA-DQA1","HLA-DQA2","HLA-DQB1","HLA-DRA","HLA-DRB1","HLA-DRB5")#GO_BP
Lymphatic_EC <- c("LYVE1","PROX1",'FLT4','CCL21','PDPN')#Lymphatic endothelial cells
#胶原蛋白

connexin <- c('CLDN10','GJA5','GJA4','FBLIM1')#编码紧密和间隙连接蛋白的基因
ECM_protein <- c('FBLN5','FBLN2','MGP','BGN','LTBP4','LTBP1','FN1')#表达有助于壁弹性和强度的细胞外基质蛋白
arterial_regulor <- c('DKK2','DLL4','HEY1','SOX5','SOX17','HES4','PRDM16')
#PMID：34030460:动脉 EC 暴露于相关的透壁压力和剪切应力。为了承受这些力，动脉 EC 表达编码紧密和间隙连接蛋白的基因，例如 CLDN10、GJA5、GJA4 和 FBLIM1;有助于壁弹性和强度的细胞外基质蛋白，例如 FBLN5、FBLN2、MGP、BGN、LTBP4、LTBP1 和 FN1
#动脉内皮细胞是活跃的分泌细胞，表达信号分子，如CXCL12、EFBN2、SEMA3G、VEGFA 和参与调节血管张力的一氧化氮途径酶，如 NOS1、PDE3A 和 PDE4D。通过表达 Wnt 信号调节剂 DKK2、Notch 配体 DLL4 和转录因子 HEY1、SOX5、SOX17、HES4 和 PRDM16 来维持其动脉身份



markers <- c(development,antigen_presentation,Lymphatic_EC,connexin,ECM_protein,arterial_regulor)

data.anno  <- data.frame(label = c(rep("DevEC",length(development)),
                                   rep("APEC",length(antigen_presentation)),
                                   rep("LymphEC",length(Lymphatic_EC)),
                                   rep("connexin",length(connexin)),
                                   rep("ECM_protein",length(ECM_protein)),
                                   
                                   rep("arterial_regulor",length(arterial_regulor))
                                   ),
                         features.plot = markers)

#获取Seurat气泡图的绘图数据
