df.plot$label <- factor(df.plot$label,levels = c('APEC','DevEC','connexin','ECM_protein','arterial_regulor','LymphEC'))

# #重绘气泡图并基于facet分面方法为x轴添加注释标签

ggplot(df.plot,aes(x=features.plot,y =  as.numeric(id),size = pct.exp, color = avg.exp.scaled))+
  geom_point() + 
