####____[6]特定亚群间差异基因#######
scRNA_sub[["RNA"]]@counts<-as.matrix(scRNA_sub[["RNA"]]@counts)+1

#阈值确定：
pvalue = 0.05
log2FC = 1

de_12 <- FindMarkers(scRNA_sub,ident.1  = "EC_1",ident.2 = "EC_2",test.use = 'wilcox',min.pct = 0.25,verbose = T)
de_12$gene <- rownames(de_12)

#根据阈值添加上下调分组标签：
de_12$DE <- case_when(
  de_12$avg_log2FC > log2FC & de_12$p_val < pvalue ~ "EC_1",
  de_12$avg_log2FC < -log2FC & de_12$p_val < pvalue ~ "EC_2",
  TRUE ~ 'none'
)
#转换为因子，指定绘图顺序；
de_12$'-log10(pvalue)' <- -log10(de_12$p_val) #新增-log10p列
de_12[which(de_12$`-log10(pvalue)` > 304.7285),'-log10(pvalue)'] <- 306 #305.6064305.6064
de_12$DE <- factor(de_12$DE, levels = c("EC_1","EC_2","none"))

write.table(de_12,"6_DE_gene_12.txt",sep = "\t",row.names = F,col.names = T,quote = F)

####_________火山图####

de_12 <- read.table("6_DE_gene_12.txt",sep = "\t",header = T,check.names = F,stringsAsFactors = F)

de_12_sig <- de_12[which(de_12$p_val < 0.05 & abs(de_12$avg_log2FC) > 1),]



color_raw <- c('#0067aa',"#ff7f00",'#00a23f',"#ff1f1d","#a763ac","#b45b5d","#b6b800","#01c1cc","#85d5f8",'#FF8AB6')
#自定义颜色：
mycol <- c("#0067aa","#ff7f00","#d8d8d8")

library(ggrepel)
diff12 <- de_12 %>%
  mutate(Difference = pct.1 - pct.2) 


ggplot(diff12, aes(x=Difference, y=avg_log2FC, color = DE)) + 
  geom_point(size=0.8,alpha = 0.8) + 
  scale_color_manual(values=mycol) +
  geom_text_repel(data = subset(diff12,gene %in% intersect(unique(cell_cell_gene$Gene),de_12_sig$gene)),
                  aes(label = gene),
                  color="black", #设置label中标签的颜色
                  segment.colour = "black",#设置label框的颜色
                  label.padding = 0.1,
                  max.overlaps = 200,
                  segment.size = 0,  #框的大小
                  size=3)+
  ggtitle("EC_1 vs EC_2") +
  geom_vline(xintercept = 0.0,linetype=2)+
