####____[7]分化-Monocle2####
####______加载R包#####
library(monocle)
library(RColorBrewer)
library(ggplot2)
library(Seurat)
library(ggpubr)
library(tidyverse)
library(dplyr)
library(ggsignif)
library(patchwork)
library(tidydr)
library(ggforce)
library(ggrastr)
library(viridis)
library(ClusterGVis)

# data("HSMM")#cds
# data("BEAM_res")#diff_test
# data("sig_gene_names")

cds <- readRDS('7_EC_monocle2.pseudotime.cds')

####_________提取数据进行绘图####
umap <- as.data.frame(scRNA_sub@reductions[["umap"]]@cell.embeddings)
metadata <- as.data.frame(scRNA_sub@meta.data)
component <- as.data.frame(t(cds@reducedDimS))
colnames(component)=c("component1","component2")

pData(cds)$umap_2 <- umap$UMAP_2
pData(cds)$umap_1 <- umap$UMAP_1
pData(cds)$component1 <- component$component1
pData(cds)$component2 <- component$component2

data <- as.data.frame(pData(cds))


####_________查找monocle选择的高变基因####
disp_table <- dispersionTable(cds)#调用estimateDispersions计算一个平滑函数，描述每个基因在细胞中表达的方差如何根据平均值变化。

disp.genes <- subset(disp_table, mean_expression >= 0.5&dispersion_empirical >= 1*dispersion_fit)

disp.genes <- as.character(disp.genes$gene_id)
diff_test <- differentialGeneTest(cds[disp.genes,], cores = 4, 
                                  fullModelFormulaStr = "~sm.ns(Pseudotime)")#测试每个基因的差异表达作为伪时间的函数或根据指定的其他协变量。
sig_gene_names <- row.names(subset(diff_test, qval < 0.05))#以qval为指标，挑选显著
write.table(diff_test,"7_highvariant_gene_monocle.txt",sep = "\t",col.names = T,row.names = T)

diff_test <- read.table("7_highvariant_gene_monocle.txt",sep = "\t",header = T,check.names = F,stringsAsFactors = F)

plot_cell_trajectory(cds, color_by="Pseudotime", size=1,show_backbone = TRUE)


