####____箱线图####
ano2 <- data.frame('Group'=scRNA_sub@meta.data$cluster,'sample'=scRNA_sub@meta.data$sample)
# Annotation vs sample
tmp2 <- acast(ano2, Group ~ sample, fun.aggregate=length)
#head(tmp2)
# Normalise for the number of cells in each library
tmp3 <- (sweep(tmp2, 2, colSums(tmp2), FUN='/'))
tmp4 <- melt(tmp3)
names(tmp4) <- c('annot', 'sample','pc.of.sample')

tmp4$Fraction <- "AD"
tmp4[which(substr(tmp4[,2],0,1) == "C" & substr(tmp4[,2],4,4) == "T"),"Fraction"] <- "naCTL"
tmp4[which(substr(tmp4[,2],0,1) == "A" & substr(tmp4[,2],4,4) == "B"),"Fraction"] <- "AD_B"
tmp4[which(substr(tmp4[,2],0,1) == "C" & substr(tmp4[,2],4,4) == "B"),"Fraction"] <- "nCTL_B"
table(tmp4$Fraction)

tmp4$Fraction=ordered(as.factor(tmp4$Fraction), levels = c('naCTL','AD','nCTL_B','AD_B'))
### barplot
lis=list()

for(i in 1:length(unique(tmp4$annot))){
  tmp=tmp4[tmp4[,1]==unique(tmp4$annot)[i],]
  sig=compare_means(pc.of.sample ~ Fraction,  data = tmp)
  sig=sig[sig$p.signif!='ns',]
  print(unique(tmp4$annot)[i])
  print(sig)
  p1 <- ggplot(tmp, aes(x=Fraction,fill=Fraction,y=pc.of.sample)) +
    geom_boxplot(outlier.shape = -1,width=0.3,position=position_dodge(width=0.1))+ 
    facet_wrap(~annot,scales="free_y")  + 
    theme_bw() + 
    theme(axis.text.x = element_text(angle = 90, hjust = 1)) + 
    theme(axis.text.x=element_blank()) + 
    xlab("")  + ylab("")
  p1=p1+theme(strip.background = element_rect(fill=color[i]),strip.text = element_text(colour = 'black'))+ theme(legend.position="none")
  p1=p1+stat_summary(fun.y=median,linetype="dotted", geom="smooth",size=0.8, aes(group=0),color='gray30')+scale_fill_manual(values=color_group)
  lis[[i]]=p1
  p1
}
c <- cowplot::plot_grid(plotlist=lis, ncol=3)
c
