for (i in 1:length(markers)) {
  a <- markers_anno[markers_anno$gene==markers[i],]
  data.anno[i,2] <- as.character(a[1,2])
  data.anno[i,1] <- paste(a[,1],collapse = ",")
}
data.anno <- as.data.frame(data.anno)
colnames(data.anno) <- c('label',"features.plot")


#获取Seurat气泡图的绘图数据
data.usage <- DotPlot(scRNA_sub,features = unique(markers))$data 

#创建x轴分类标签注释
# data.anno <- cell_marker[which(cell_marker[,2] %in% markers),]
# colnames(data.anno) <- c("label","features.plot")
#将注释添加到data.usage方便绘图调用
df.plot <- plyr::join(data.usage,data.anno)

# 
# #根据需求重排y轴绘图标签顺序
# df.plot$id <- factor(df.plot$id,levels = c(0,5,6,9,10,4,2,3,1,8,11,7) )
# 
df.plot$label <- factor(df.plot$label,levels = c('MonocyteDerivedMacrophage','ProliferatingM2','M1Macrophages_1','M1Macrophages_2','M2Macrophages_1','M2Macrophages_2'))

#重绘气泡图并基于facet分面方法为x轴添加注释标签

p <- ggplot(df.plot,aes(x=features.plot,y =  as.numeric(id),size = pct.exp, color = avg.exp.scaled))+
  geom_point() + 
  scale_size("% detected", range = c(0,10)) + #调整绘图点的相对大小
  scale_color_gradientn(colours = c("blue","white","red"),limits = c(-2.5,2.5),name = "Average\nexpression") +
  cowplot::theme_cowplot() + 
  ylab("") + xlab("Markers") + theme_bw() +
  scale_y_continuous(breaks = 1:length(levels(df.plot$id)),labels = levels(df.plot$id),sec.axis = dup_axis())+ #复制 y轴 代替边框效果
  facet_grid(~label, scales="free",space = "free")+
  theme_classic() +
  theme(
    axis.text.x = element_text(size=12, angle=45, hjust=1),#x轴标签样式
    axis.text.y = element_text(size=12),
    axis.title.x = element_text(size=14,vjust = -0.8,hjust = 0.5),#坐标轴标题
    axis.ticks.y = element_blank(),#坐标轴刻度
    axis.text.y.right = element_blank(),#坐标轴标签隐藏
    axis.ticks.x = element_blank(),
    axis.line = element_line(colour = 'grey30',size = 0.2), #坐标轴轴线样式
    panel.spacing=unit(0, "mm"), #分面图图块间距
    strip.text.x = element_text(size=12,color = "#FFFFFF",
                                vjust = 0.5,margin = margin(b = 3,t=3)),#分面标签样式
    strip.background = element_rect(colour="grey30", fill="grey60",size = 0.5)
  )
g <- change_strip_background(p, type = "top", strip.color = color_raw)

