####____[5]特定亚群间差异基因#######
scRNA_sub[["RNA"]]@counts<-as.matrix(scRNA_sub[["RNA"]]@counts)+1

#阈值确定：
pvalue = 0.05
log2FC = 1

de_21 <- FindMarkers(scRNA_sub,ident.1  = "M2Macro",ident.2 = "M1Macro",test.use = 'wilcox',min.pct = 0.25,verbose = T)
de_21$gene <- rownames(de_21)

#根据阈值添加上下调分组标签：
de_21$DE <- case_when(
  de_21$avg_log2FC > log2FC & de_21$p_val < pvalue ~ "M2Macro",
  de_21$avg_log2FC < -log2FC & de_21$p_val < pvalue ~ "M1Macro",
  TRUE ~ 'none'
)
#转换为因子，指定绘图顺序；
de_21$'-log10(pvalue)' <- -log10(de_21$p_val) #新增-log10p列
de_21[which(de_21$`-log10(pvalue)` > 305.5755),'-log10(pvalue)'] <- 306 #305.6064305.6064
de_21$DE <- factor(de_21$DE, levels = c("M2Macro","M1Macro","none"))

write.table(de_21,"5_DE_gene_M2Macro_M1Macro.txt",sep = "\t",row.names = F,col.names = T,quote = F)

####_________火山图####

de_21 <- read.table("5_DE_gene_M2Macro_M1Macro.txt",sep = "\t",header = T,check.names = F,stringsAsFactors = F)

de_21_sig <- de_21[which(de_21$p_val < 0.05 & abs(de_21$avg_log2FC) > 1),]



color_raw <- c('#0067aa',"#ff7f00",'#00a23f',"#ff1f1d","#a763ac","#b45b5d","#b6b800","#01c1cc","#85d5f8",'#FF8AB6')
#自定义颜色：
mycol <- c("#a763ac","#00a23f","#d8d8d8")

library(ggrepel)
diff12 <- de_21 %>%
  mutate(Difference = pct.1 - pct.2) 


ggplot(diff12, aes(x=Difference, y=avg_log2FC, color = DE)) + 
  geom_point(size=0.8,alpha = 0.8) + 
  scale_color_manual(values=mycol) +
  geom_text_repel(data = subset(diff12,gene %in% intersect(unique(c(MHC_gene)),de_21_sig$gene)),
                  aes(label = gene),
                  color="black", #设置label中标签的颜色
