                  label.padding = 0.1,
                  max.overlaps = 200,
                  segment.size = 0,  #框的大小
                  size=3)+
  ggtitle("M2Macro vs M1Macro") +
  geom_vline(xintercept = 0.0,linetype=2)+
  geom_hline(yintercept = -1,linetype=2)+
  geom_hline(yintercept = 1,linetype=2)+
  theme_classic(base_size = 12)+#改变图例大小  
  theme(plot.title = element_text(vjust = 0.5,hjust = 0.5))#标题居中
ggsave("5_DE_volcano_MHC_gene.pdf",width = 5,height = 4)

ggplot(diff12, aes(x=Difference, y=avg_log2FC, color = DE)) + 
