ordergene <- unique(network_monocle_DE[,"Gene"])


cds<-readRDS("./Ex-cds3.rds")
head(rownames(cds))
# [1] "MTND2P28"      "hsa-mir-6723"  "MTATP6P1"      "RP5-857K21.11" "NOC2L"         "HES4"      

meta <- scRNA_sub@meta.data

#这里是把排序基因（ordergene）提取出来做回归分析，来找它们是否跟拟时间有显著的关系
#如果不设置，就会用所有基因来做它们与拟时间的相关性
Time_diff <- differentialGeneTest(cds[ordergene,], cores = 1, 
                                  fullModelFormulaStr = "~sm.ns(Pseudotime)")

Time_diff <- Time_diff[,c(5,2,3,4,1,6,7)] #把gene放前面，也可以不改

Time_genes <- Time_diff %>%  
  arrange(qval) %>%  # 按 qval 降序排列  
  #slice_head(n = 30) %>%  # 选择前 30 行  
  pull(gene_short_name) %>% # 提取基因名称  
  as.character()            # 转换为字符向量  

p <- plot_pseudotime_heatmap(cds[Time_genes,], num_clusters=5, show_rownames=T, return_heatmap=T)

save(Time_diff,p,Time_genes,file = "7_2_Pseudotime_TF_DEgene_cluster_enrich5.rda")

p$tree_row
# Call:
#   hclust(d = d, method = method)
# 
# Cluster method   : ward.D2 
# Number of objects: 30

# gene_cluster
clusters <- cutree(p$tree_row, k = 5)
clustering <- data.frame(clusters)
clustering[,1] <- as.character(clustering[,1])
colnames(clustering) <- "Gene_Clusters"
table(clustering$Gene_Clusters)
# Gene_Clusters
# 1 2 3 4 5 
# 4 9 6 9 2 

hp.genes<-p$tree_row$labels[p$tree_row$order]
Time_diff_sig<-Time_diff[hp.genes,c("gene_short_name","pval","qval")]
Time_diff_sig$cluster <- clustering$Gene_Clusters[ match(Time_diff_sig$gene_short_name, rownames(clustering)) ]

View(cds@phenoData@data)
genename = dimnames(scRNA_sub@assays[["RNA"]]@features)[[1]]
cellname=dimnames(scRNA_sub@assays[["RNA"]]@cells)[[1]]
data<-as.data.frame(scRNA_sub@assays[["RNA"]]@layers[["data"]])
rownames(data)<-genename
colnames(data)<-cellname
data_time<-as.data.frame(t(data[Time_genes,]))

data <- as.data.frame(scRNA_sub@assays$RNA@data)
data_time<-as.data.frame(t(data[Time_genes,rownames(pData(cds))]))


# ductal按伪时间为顺序为细胞排序，作为列，基因为行
data_time$Pseudotime <- cds@phenoData@data$Pseudotime
# 对同一时间的细胞进行取平均

data_time1 <-  aggregate(data_time, by=list(spot_label = data_time$Pseudotime), FUN=mean)


# 按伪时间升序排列
data_time1 <- data_time1[order(data_time1$Pseudotime,decreasing=F),]

# 进行于赫师兄推荐的标准化
data_time2 <- data_time1[,-c(1,59)]
data_time2 <- as.data.frame(t(data_time2))

data_time2 <- t(apply(data_time2,1,function(x){smooth.spline(x,df=3)$y}))
data_time2 <- t(apply(data_time2,1,function(x){(x-mean(x))/sd(x)}))

#转置，使得行为基因，列为细胞
data_time2 <- as.data.frame(data_time2)

# save
write.csv(data_time2, "7_2_Pseudotime_TF_DEgene_range_origin.csv", row.names = T)
save(data_time,data_time2, file = "7_2_Pseudotime_TF_DEgene_range_origin.rda")



