####________各亚型在疾病与正常分组中上调差异基因的GO####
####aPEAR

# ##'@安装aPEAR包
# library(devtools)
# install_github('ievaKer/aPEAR')

#加载所需的包
library(aPEAR)
library(clusterProfiler)
library(org.Hs.eg.db)
library(DOSE)
library(ggplot2)

sub_cluster <- names(table(scRNA_sub$cluster))

for (j in c(1,6)) {
  sub <- sub_cluster[j]
  group <- "ADvsnaCTL"
  top <- 30
  result_GO <- read.table(paste0("4_",sub,"_",group,"_up.GOALL_sig.txt"),sep = "\t",header = T,stringsAsFactors = F,check.names = F)
  result_GO_BP <- result_GO[which(result_GO$ONTOLOGY == "BP"),-1]
  
  result_GO_BP_top <- result_GO_BP[order(result_GO_BP$p.adjust,decreasing = F),]
  if(nrow(result_GO_BP) > top){
    result_GO_BP_top <- result_GO_BP_top[1:top,]
  }
  
  a <- enrichmentNetwork(result_GO_BP_top, 
                         colorBy = 'p.adjust', 
                         colorType = 'nes')+
    scale_color_gradientn(colours = c("#F90016",'#251DFA'),
                          name = "p.adjust")
  ggsave(paste0("4_",sub,"_",group,"_up_top",top,".GO.pdf"),a,width = 8,height = 8)
  
  
  result <- as.data.frame(a$plot_env$clust)
  result$GO_BP <- rownames(result)
  colnames(result)[1] <- "Class"
  
  result$subcluster <- sub
  if(j == 1){
    result_all <- result
  }else{
    result_all <- rbind(result_all,result)
  }
  
  print(sub)
}
write.table(result_all,"4_16_GP_BP_up_pathway_class.txt",col.names = T,row.names = F,sep = "\t")


