#提前算好合并成的数据是几行几列，length(GID)行，2列#
for (i in 1:length(markers)) {
  a <- markers_anno[markers_anno$gene==markers[i],]
  data.anno[i,2] <- as.character(a[1,2])
  data.anno[i,1] <- paste(substr(a[,1],nchar(a[,1]),nchar(a[,1])),collapse = ",")
}
data.anno <- as.data.frame(data.anno)
colnames(data.anno) <- c('label',"features.plot")


