####________各亚型特征基因GO富集分析####
####aPEAR

# ##'@安装aPEAR包
# library(devtools)
# install_github('ievaKer/aPEAR')

#加载所需的包
library(aPEAR)
library(clusterProfiler)
library(org.Hs.eg.db)
library(DOSE)
library(ggplot2)

sub_cluster <- names(table(scRNA_sub_blood$cluster))

for (j in 1:length(sub_cluster)) {
  sub <- sub_cluster[j]
  top <- 30
  markers <- as.character(all_markers[which(all_markers$cluster == sub &
                                 all_markers$avg_log2FC > 0.25 & 
                                 all_markers$p_val < 0.05 &
                                 all_markers$p_val_adj <= 1),"gene"])

  result_GO_all <- enrichGO(markers,'org.Hs.eg.db',keyType = "SYMBOL", ont="BP")
  result_GO <- result_GO_all[which(result_GO_all$p.adjust < 0.05 & result_GO_all$Count >= 3),]
  write.table(result_GO,paste0("4_",sub,"_blood_up.GOALL_sig.txt"),col.names = T,row.names = F,sep = "\t")

  result_GO_BP <- result_GO
  
  result_GO_BP_top <- result_GO_BP[order(result_GO_BP$p.adjust,decreasing = F),]
  if(nrow(result_GO_BP) > top){
    result_GO_BP_top <- result_GO_BP_top[1:top,]
  }
  
  a <- enrichmentNetwork(result_GO_BP_top, 
                         colorBy = 'p.adjust', 
                         colorType = 'nes')+
    scale_color_gradientn(colours = c("#F90016",'#251DFA'),
                          name = "p.adjust")
  ggsave(paste0("4_",sub,"_blood_up_top",top,".GO.pdf"),a,width = 8,height = 8)
  
  
  result <- as.data.frame(a$plot_env$clust)
  result$GO_BP <- rownames(result)
  colnames(result)[1] <- "Class"
  
  result$subcluster <- sub
  if(j == 1){
    result_all <- result
  }else{
    result_all <- rbind(result_all,result)
  }
  
  print(sub)
}
write.table(result_all,"4_blood_signature_GP_BP_pathway_class.txt",col.names = T,row.names = F,sep = "\t")


