####______与对照相比，AD的扩增缺失基因集####
ctl_amp_gene <- unique(muta_gene_ctl_amp[,1])
ad_amp_gene <- unique(muta_gene_ad_amp[,1])
amp_gene <- setdiff(ad_amp_gene,ctl_amp_gene)
amp_gene_gencode <- gencode[which(gencode[,5] %in% amp_gene),c(1:3,5)]
amp_gene_gencode <- amp_gene_gencode[!duplicated(amp_gene_gencode),]

ctl_del_gene <- unique(muta_gene_ctl_del[,1])
ad_del_gene <- unique(muta_gene_ad_del[,1])
del_gene <- setdiff(ad_del_gene,ctl_del_gene)
del_gene_gencode <- gencode[which(gencode[,5] %in% del_gene),c(1:3,5)]
del_gene_gencode <- del_gene_gencode[!duplicated(del_gene_gencode),]

muta_gene_amp <- muta_gene_ad_amp[which(muta_gene_ad_amp$gene %in% amp_gene),]
muta_gene_del <- muta_gene_ad_del[which(muta_gene_ad_del$gene %in% del_gene),]
