ggplot(data = gene_num_num, aes(x=chr, y=sub)) + 
  geom_point(aes(color=count,size = abs(count)),shape=15)+
  scale_color_gradient2(low = "#0099cc", mid = "white", high = "#cc0033", midpoint = 0,space = "Lab") +
  # 背景格子纵横比为1，即正方形
  coord_equal()+
  labs(color = "CNV gene count") +
