ego_amp <- enrichGO(gene = amp_gene$symbol,
                    OrgDb ='org.Hs.eg.db',
                    keyType = "SYMBOL",
                    ont = 'BP',#设置为ALL时BP,cC,MF都计算
                    pAdjustMethod = "BH",
                    pvalueCutoff = 0.05,
                    qvalueCutoff = 1)
ego_amp <- as.data.frame(ego_amp)
if(nrow(ego_amp) > 0){
  ego_amp$log10p <- -log10(ego_amp$pvalue)
  ego_amp$cell_type <- cell
  ego_amp$CNV <- "amp"
  write.table(ego_amp,paste0(dir_result,"\\",group,"\\",cell,"\\2_",cell,"_all_AD_amp_gene_GOBP.txt"),sep = "\t",col.names = T,row.names = F)
}

ego_del <- enrichGO(gene = del_gene$symbol,
                    OrgDb ='org.Hs.eg.db',
                    keyType = "SYMBOL",
                    ont = 'BP',#设置为ALL时BP,cC,MF都计算
                    pAdjustMethod = "BH",
                    pvalueCutoff = 0.05,
                    qvalueCutoff = 1)
ego_del <- as.data.frame(ego_del)
if(nrow(ego_del) > 0){
  ego_del$log10p <- -log10(ego_del$pvalue)
  ego_del$cell_type <- cell
  ego_del$CNV <- "del"
  write.table(ego_del,paste0(dir_result,"\\",group,"\\",cell,"\\2_",cell,"_all_AD_del_gene_GOBP.txt"),sep = "\t",col.names = T,row.names = F)
}

####_______绘制功能富集

#每种celltype我们选个10条terms可视化

ego_del$log10p <- -ego_del$log10p
ego_all <- rbind(ego_amp,ego_del)
ego_all <- ego_all %>% 
  group_by(CNV) %>% 
  top_n(5,-p.adjust)
#将需要展示的通路展示在一起
ggplot(ego_all) +
  ggforce::geom_link(data = ego_all, 
                     aes(x = 0,
                         y = reorder(Description, -log10p),
                         xend =log10p,
                         yend = Description,
                         colour=CNV,
                         alpha = after_stat(index),
                         size = after_stat(index)),
                     show.legend = F)+
  coord_fixed(ratio = 2)+
  geom_point(data = ego_all,
             aes(x = log10p, y = Description),
             size=6,
             shape = 21,
             fill = "white")+
  scale_colour_manual(values = color_CNV)+
  geom_text(mapping=aes(x=log10p,
                        y=Description,
                        label=Count),
            size =2.5,color="black")+
  geom_vline(xintercept = -log10(0.05),
             color = "grey60",
             linetype=2, cex=0.5)+
  geom_vline(xintercept = log10(0.05),
             color = "grey60",
             linetype=2, cex=0.5)+
  theme_classic()+
  theme(axis.title.y = element_blank(),
        axis.text = element_text(colour = 'black'))+
  labs(x="-Log10(P-value)")
ggsave(paste0(dir_result,"\\",group,"\\",cell,"\\2_",cell,"_all_AD_CNV_gene_top5_GOBP.pdf"),width = 7,height = 3)


