####____[2.4]Macro####
c <- 5
cell <- cells[c]
dir.create(paste0(dir_result,"\\",group,"\\",cell))

sub_clusters <- list.files(paste0(dir_mutaG,"\\",group,"\\",cell))

muta_gene_amp <- data.frame()
muta_gene_del <- data.frame()

for (s in 1:length(sub_clusters)) {
  ####_________细胞亚簇####
  sub <- sub_clusters[s]
  files <- list.files(paste0(dir_mutaG,"\\",group,"\\",cell,"\\",sub))
  n <- length(files)
  
  #识别该细胞亚簇在一个或两个分组中出现
  ####______该亚簇在两组中出现####
  if(n == 6){
    class <- "diff"
    
    #读取该簇在不同分组中的突变基因
    ad_muta_gene <- read.table(paste0(dir_mutaG,"\\",group,"\\",cell,"\\",sub,"\\",files[1]),sep = ",",header = T,row.names = 1)
    ctl_muta_gene <- read.table(paste0(dir_mutaG,"\\",group,"\\",cell,"\\",sub,"\\",files[2]),sep = ",",header = T,row.names = 1)
    
    #提取显著的突变基因
    ad_muta_gene_sig <- ad_muta_gene[which(abs(ad_muta_gene$cnv) > 0.02),]
    ad_muta_gene_sig_amp <- ad_muta_gene_sig[which(ad_muta_gene_sig$cnv > 0),]
    ad_muta_gene_sig_del <- ad_muta_gene_sig[which(ad_muta_gene_sig$cnv < 0),]
    
    ctl_muta_gene_sig <- ctl_muta_gene[which(abs(ctl_muta_gene$cnv) > 0.02),]
    ctl_muta_gene_sig_amp <- ctl_muta_gene_sig[which(ctl_muta_gene_sig$cnv > 0),]
    ctl_muta_gene_sig_del <- ctl_muta_gene_sig[which(ctl_muta_gene_sig$cnv < 0),]
    
    
    #与正常相比，疾病的显著扩增或缺失基因
    ####____________提取显著扩增或缺失基因####
    muta_gene_sig_amp <- ad_muta_gene_sig_amp[setdiff(rownames(ad_muta_gene_sig_amp),rownames(ctl_muta_gene_sig_amp)),]
    muta_gene_sig_del <- ad_muta_gene_sig_del[setdiff(rownames(ad_muta_gene_sig_del),rownames(ctl_muta_gene_sig_del)),]
    
    muta_gene_sig_amp <- cbind(rownames(muta_gene_sig_amp),muta_gene_sig_amp)
    muta_gene_sig_del <- cbind(rownames(muta_gene_sig_del),muta_gene_sig_del)
    colnames(muta_gene_sig_amp)[1] <- colnames(muta_gene_sig_del)[1] <- "gene"
    
    if(nrow(muta_gene_sig_amp) > 0){
      write.table(muta_gene_sig_amp,paste0(dir_result,"\\",group,"\\",cell,"\\1_",cell,"_",sub,"_",class,"_amp_gene.txt"),sep = "\t",row.names = F,col.names = T)
      
      muta_gene_sig_amp$sub_cluster <- sub
      muta_gene_sig_amp$group <- "AD"
      muta_gene_sig_amp$CNV <- "amp"
      muta_gene_amp <- rbind(muta_gene_amp,muta_gene_sig_amp)
    }
    
    if(nrow(muta_gene_sig_del) > 0){
      write.table(muta_gene_sig_del,paste0(dir_result,"\\",group,"\\",cell,"\\1_",cell,"_",sub,"_",class,"_del_gene.txt"),sep = "\t",row.names = F,col.names = T)
      
      muta_gene_sig_del$sub_cluster <- sub
      muta_gene_sig_del$group <- "AD"
      muta_gene_sig_del$CNV <- "del"
      muta_gene_del <- rbind(muta_gene_del,muta_gene_sig_del)
    }
    
    #扩增基因
    gencode_c <- gencode[which(gencode[,5] %in% rownames(muta_gene_sig_amp)),c(1:3,5)]
    gencode_c <- gencode_c[!duplicated(gencode_c$symbol),]
    
    #缺失基因
    gencode_d <- gencode[which(gencode[,5] %in% rownames(muta_gene_sig_del)),c(1:3,5)]
    gencode_d <- gencode_d[!duplicated(gencode_d$symbol),]
    
    title <- c(sub,paste0("amp gene : ",length(unique(gencode_c$symbol))),paste0("del gene : ",length(unique(gencode_d$symbol))))
    
    if(nrow(gencode_c) == 0 & nrow(gencode_d) == 0){
      print(paste0(sub," don't have CNV gene"))
    }else{
      ####____________绘制扩增或缺失基因####
      pdf(paste0(dir_result,"\\",group,"\\",cell,"\\1_",cell,"_",sub,"_",class,"_gene.pdf"),height = 7,width = 7)
      # 导入上面四个基本参数
      RCircos.Set.Core.Components(cyto.info ,
                                  chr.exclude = NULL,# 设置不显示的染色体，如 c(1,3)
                                  tracks.inside = 2, # 设置内部环形个数
                                  tracks.outside = 2 # 设置外部环形个数
      )
      # 列出所有绘图参数
      #RCircos.List.Plot.Parameters()
      # 绘制染色体图形，默认方法显示染色体名称。
      RCircos.Set.Plot.Area()
      RCircos.Chromosome.Ideogram.Plot()
      
      #####更改circos图颜色参数
      params=RCircos.Get.Plot.Parameters()
      params$heatmap.color = "BlackOnly"
      #params$hist.color="orchid"###直方图颜色更改
      params$scatter.color="tan"###散点图颜色更改
      params$track.background <- "white"
      RCircos.Reset.Plot.Parameters(params)
      
      #绘制扩增基因
      if(nrow(gencode_c) > 0){
        #添加指定基因名的线段
        RCircos.Gene.Connector.Plot(gencode_c,
                                    track.num = 1, ## 指定内容在第几个环形生成
                                    side = "out" # 指定内容在内侧的环形还是外侧的环形生成
        );
        
        # 在染色体上添加基因名称
        RCircos.Gene.Name.Plot(gencode_c,
                               name.col = 4,#表示输入数据中包含基因名称的列
                               track.num =2, #指定内容在第几个环形生成
                               side = "out")
        #RCircos.List.Plot.Parameters() #展示所有参数
        
      }
      
      #绘制缺失基因
      if(nrow(gencode_d) > 0){
        #添加指定基因名的线段
        RCircos.Gene.Connector.Plot(gencode_d,
                                    track.num = 1, ## 指定内容在第几个环形生成
                                    side = "in" # 指定内容在内侧的环形还是外侧的环形生成
        );
        
        # 在染色体上添加基因名称
        RCircos.Gene.Name.Plot(gencode_d,
                               name.col = 4,#表示输入数据中包含基因名称的列
                               track.num =2, #指定内容在第几个环形生成
                               side = "in")
        #RCircos.List.Plot.Parameters() #展示所有参数
        
      }
      
      title(paste(title,sep = "\n"),outer = F)
      dev.off()
      #运行完这一句清除画板内容
      
    }
    
    ####____________扩增或缺失基因功能富集####
    ####______________GO####
    ego_amp <- enrichGO(gene = rownames(muta_gene_sig_amp),
                        OrgDb ='org.Hs.eg.db',
                        keyType = "SYMBOL",
                        ont = 'BP',#设置为ALL时BP,cC,MF都计算
                        pAdjustMethod = "BH",
                        pvalueCutoff = 0.05,
                        qvalueCutoff = 1)
    ego_amp <- as.data.frame(ego_amp)
    if(nrow(ego_amp) > 0){
      
      #将分数字符转化为小数
      ego_amp <- ego_amp %>%
        separate(GeneRatio,c("gene_in","gene_back"),"/") %>%
        mutate(GeneRatio = as.numeric(gene_in)/as.numeric(gene_back))
      
      ego_amp$log10p <- -log10(ego_amp$pvalue)
      ego_amp$cell_type <- cell
      ego_amp$sub_cluster <- sub
      ego_amp$CNV <- "amp"
      
      ego_amp <- ego_amp[order(ego_amp$log10p,ego_amp$Count,decreasing = T),]
      
      write.table(ego_amp,paste0(dir_result,"\\",group,"\\",cell,"\\2_",cell,"_",sub,"_",class,"_amp_GOBP.txt"),sep = "\t",col.names = T,row.names = F)
    }
    
    ego_del <- enrichGO(gene = rownames(muta_gene_sig_del),
                        OrgDb ='org.Hs.eg.db',
                        keyType = "SYMBOL",
                        ont = 'BP',#设置为ALL时BP,cC,MF都计算
                        pAdjustMethod = "BH",
                        pvalueCutoff = 0.05,
                        qvalueCutoff = 1)
    ego_del <- as.data.frame(ego_del)
    if(nrow(ego_del) > 0){
      #将分数字符转化为小数
      ego_del <- ego_del %>%
        separate(GeneRatio,c("gene_in","gene_back"),"/") %>%
        mutate(GeneRatio = as.numeric(gene_in)/as.numeric(gene_back))
      
      ego_del$log10p <- -log10(ego_del$pvalue)
      ego_del$cell_type <- cell
      ego_del$sub_cluster <- sub
      ego_del$CNV <- "del"
      ego_del <- ego_del[order(ego_del$log10p,ego_del$Count,decreasing = T),]
      ego_del$Count <- -ego_del$Count
      
      if(nrow(ego_amp) > 0){
        top <- 10
        ego_all <- rbind(ego_amp,ego_del)
      }else{
        top <- 5
        ego_all <- ego_del
      }
      write.table(ego_del,paste0(dir_result,"\\",group,"\\",cell,"\\2_",cell,"_",sub,"_",class,"_del_GOBP.txt"),sep = "\t",col.names = T,row.names = F)
    }else{
      ego_all <- ego_amp
      top <- 5
    }
    if(nrow(ego_all) > 0){
      if(nrow(ego_amp) >= 5 & nrow(ego_del) >= 5){
        ego_all <- rbind(ego_amp[1:5,],ego_del[1:5,],ego_amp[5:nrow(ego_amp),],ego_del[5:nrow(ego_del),])
      }else if(nrow(ego_amp) >= 5 & nrow(ego_del) < 5){
        ego_all <- rbind(ego_del,ego_amp)
      }else if(nrow(ego_amp) < 5 & nrow(ego_del) >= 5){
