      }
      
      if(top == 5){
        ggsave(paste0(dir_result,"\\",group,"\\",cell,"\\2_",cell,"_",sub,"_",class,"_GO.pdf"),width = 3,height = 3)
      }else if(top == 10){
        ggsave(paste0(dir_result,"\\",group,"\\",cell,"\\2_",cell,"_",sub,"_",class,"_GO.pdf"),width = 5,height = 4)
      }
      
      
    }else{
      print(paste0(sub," : No pathways were enriched"))
    }
    print(paste0(group,": ",class,": ",cell,": ",sub,": ",class))
    
  }
}
