####___________GO####
ego_amp <- enrichGO(gene = amp_gene,
                    OrgDb ='org.Hs.eg.db',
                    keyType = "SYMBOL",
                    ont = 'BP',#设置为ALL时BP,cC,MF都计算
                    pAdjustMethod = "BH",
                    pvalueCutoff = 0.05,
                    qvalueCutoff = 1)
ego_amp <- as.data.frame(ego_amp)
if(nrow(ego_amp) > 0){
  
  #将分数字符转化为小数
  ego_amp <- ego_amp %>% 
    separate(GeneRatio,c("gene_in","gene_back"),"/") %>%
    mutate(GeneRatio = as.numeric(gene_in)/as.numeric(gene_back))
  
  ego_amp$log10p <- -log10(ego_amp$pvalue)
  ego_amp$cell_type <- cell
  ego_amp$CNV <- "amp"
  write.table(ego_amp,paste0(dir_result,"\\",group,"\\",cell,"\\2_",cell,"_all_AD_amp_gene_GOBP.txt"),sep = "\t",col.names = T,row.names = F)
}

ego_del <- enrichGO(gene = del_gene,
                    OrgDb ='org.Hs.eg.db',
                    keyType = "SYMBOL",
                    ont = 'BP',#设置为ALL时BP,cC,MF都计算
                    pAdjustMethod = "BH",
                    pvalueCutoff = 0.05,
                    qvalueCutoff = 1)
ego_del <- as.data.frame(ego_del)
if(nrow(ego_del) > 0){
  
  ego_del <- ego_del %>% 
    separate(GeneRatio,c("gene_in","gene_back"),"/") %>%
    mutate(GeneRatio = as.numeric(gene_in)/as.numeric(gene_back))
  
  ego_del$log10p<- -log10(ego_del$pvalue)
  ego_del$cell_type <- cell
  ego_del$CNV <- "del"
  
  ego_del <- ego_del[order(ego_del$log10p,ego_del$Count,decreasing = T),]
  ego_del$Count <- -ego_del$Count
  
  
  ego_all <- rbind(ego_amp,ego_del)
  
  
  write.table(ego_del,paste0(dir_result,"\\",group,"\\",cell,"\\2_",cell,"_all_AD_del_gene_GOBP.txt"),sep = "\t",col.names = T,row.names = F)
}else{
  ego_all <- ego_amp
}

####_____________GO气泡图####
if(nrow(ego_all) > 0){
  
  ego_all <- ego_all[order(ego_all$log10p,abs(ego_all$Count),decreasing = T),]
  
  
  
  
  ggplot(ego_all, aes(x = Count, y = log10p)) + #x、y轴取值限制，颜色根据"Sig"
    geom_point(aes(size=abs(ego_all$Count),color=ego_all$Count,alpha=abs(ego_all$GeneRatio))) +  #点的透明度、大小
    scale_alpha_continuous(range = c(0.3, 0.7))+
    scale_size(range=c(1,14))+
    scale_color_gradient2(low = "#0099cc", mid = "white", high = "#cc0033", midpoint = 0,space = "Lab") +
    xlim(c(min(ego_all$Count), max(ego_all$Count)+0.2))+ylim(c(2, max(ego_all$log10p)+0.2)) + #调整点的颜色和x轴的取值范围
    geom_vline(xintercept=0,lty=1,col="black",lwd=0.8) + #添加x轴辅助线,lty函数调整线的类型："twodash"、"longdash"、"dotdash"、"dotted"、"dashed"、"solid"、"blank"
    geom_hline(yintercept =0, lty=1,col="black",lwd=0.8) +  #添加y轴辅助线
    labs(x="Count", y="-log10 p value") +  #x、y轴标签
    ggtitle(paste0(cell," mutated gene GO−BP in AD")) + #标题
    theme_bw() + # 主题，help(theme)查找其他个性化设置
    theme(plot.title = element_text(hjust = 0.5),
          legend.position="right", 
          legend.title = element_blank(),
          axis.text.x = element_text(size = 12),
          axis.text.y = element_text(size = 12),
          axis.title.x = element_text(size = 14),
          axis.title.y = element_text(size = 14))+
    coord_trans(x = squash_axis(-1,1,5))+      #压缩坐标轴
    theme(legend.position = 'none')+
    geom_text(data = ego_all[1:10,],
              aes(label = Description),size = 4)
  
  if(nrow(ego_del) == 0){
    ggsave(paste0(dir_result,"\\",group,"\\",cell,"\\2_",cell,"_all_ADuni_CNV_gene_GOBP.pdf"),width = 4,height = 4)
  }else{
    ggsave(paste0(dir_result,"\\",group,"\\",cell,"\\2_",cell,"_all_ADuni_CNV_gene_GOBP.pdf"),width = 5,height = 4)
  }
} 



