#分析样本cc.naCTL的细胞通讯网络
cellchat <- cc.naCTL
cellchat@DB <- CellChatDB.human
cellchat <- subsetData(cellchat)
cellchat <- identifyOverExpressedGenes(cellchat)#鉴定与每个细胞组相关的过表达信号基因
cellchat <- identifyOverExpressedInteractions(cellchat)#识别过表达的配体-受体相互作用
#cellchat <- projectData(cellchat,PPI.human)#将基因表达数据投射到蛋白质-蛋白质相互作用网络上
cellchat <- computeCommunProb(cellchat, raw.use = TRUE, population.size = TRUE)#计算任何交互单元组之间的通信概率/强度
#cellchat <- filterCommunication(cellchat, min.cells = 5)
cellchat <- computeCommunProbPathway(cellchat)#通过汇总所有相关的配体/受体，计算信号通路水平上的通信概率

cellchat <- aggregateNet(cellchat)#通过计算链路数或汇总通信概率来计算聚合网络

cellchat <- netAnalysis_computeCentrality(cellchat, slot.name = "netP")#计算网络中心性得分，从而识别所有推断通信网络中的主要发送者、接收者、调解者和影响者
