                                          group.dataset = "Group", 
                                          pos.dataset = pos.dataset, 
                                          features.name = features.name, 
                                          only.pos = FALSE,
                                          thresh.pc = 0, 
                                          thresh.fc = 0, 
                                          thresh.p = 1)
net_CM_diff <- netMappingDEG(cellchat_CM, features.name = features.name)
