cc.naCTL_pht <- createCellChat(scRNA_naCTL_phenotype@assays$RNA@data, meta = scRNA_naCTL_phenotype@meta.data, group.by = "cluster")

cc.naCTL_pht@DB <- CellChatDB.human
cc.naCTL_pht <- subsetData(cc.naCTL_pht)
cc.naCTL_pht <- identifyOverExpressedGenes(cc.naCTL_pht)#鉴定与每个细胞组相关的过表达信号基因
cc.naCTL_pht <- identifyOverExpressedInteractions(cc.naCTL_pht)#识别过表达的配体-受体相互作用
cc.naCTL_pht <- projectData(cc.naCTL_pht,PPI.human)#将基因表达数据投射到蛋白质-蛋白质相互作用网络上
cc.naCTL_pht <- computeCommunProb(cc.naCTL_pht, raw.use = TRUE, population.size = TRUE)#计算任何交互单元组之间的通信概率/强度
