cc.naCTL_pht <- aggregateNet(cc.naCTL_pht)#通过计算链路数或汇总通信概率来计算聚合网络

cc.naCTL_pht <- netAnalysis_computeCentrality(cc.naCTL_pht, slot.name = "netP")#计算网络中心性得分，从而识别所有推断通信网络中的主要发送者、接收者、调解者和影响者
