saveRDS(cc.naCTL_pht, "0_cc.naCTL_phenotype.rds")
cc.naCTL_pht <- readRDS("0_cc.naCTL_phenotype.rds")

####________AD#####
phenotypes_ad <- c("AngEC","SynSMC1","SynSMC2","InfFib","ConMyo","M1Macro")#,"Pro_SynSMC_1","Pro_SynSMC_2"
color_phenotype_AD <- c(
  "AngEC" = "#FCCF3E",
  "SynSMC1" = "#8770AC",
  "SynSMC2" = "#8770AC",
  "InfFib" = "#64BEDD",
  "ConMyo" = "#64BEDD",
  "M1Macro" = "#FF7B46"
)#"Pro_SynSMC_1" = "#8770AC","Pro_SynSMC_2" = "#8770AC",

scRNA_AD_phenotype <- subset(scRNA,Group == "AD"  & cluster %in% phenotypes_ad)
scRNA_AD_phenotype$cluster <- factor(scRNA_AD_phenotype$cluster,levels = phenotypes_ad)
Idents(scRNA_AD_phenotype) <- "cluster"

### 创建cellchat对象
cc.AD_pht <- createCellChat(scRNA_AD_phenotype@assays$RNA@data, meta = scRNA_AD_phenotype@meta.data, group.by = "cluster")

cc.AD_pht@DB <- CellChatDB.human
cc.AD_pht <- subsetData(cc.AD_pht)
cc.AD_pht <- identifyOverExpressedGenes(cc.AD_pht)#鉴定与每个细胞组相关的过表达信号基因
cc.AD_pht <- identifyOverExpressedInteractions(cc.AD_pht)#识别过表达的配体-受体相互作用
cc.AD_pht <- projectData(cc.AD_pht,PPI.human)#将基因表达数据投射到蛋白质-蛋白质相互作用网络上
cc.AD_pht <- computeCommunProb(cc.AD_pht, raw.use = TRUE, population.size = TRUE)#计算任何交互单元组之间的通信概率/强度
#cc.AD_pht <- filterCommunication(cc.AD_pht, min.cells = 5)
cc.AD_pht <- computeCommunProbPathway(cc.AD_pht)#通过汇总所有相关的配体/受体，计算信号通路水平上的通信概率

cc.AD_pht <- aggregateNet(cc.AD_pht)#通过计算链路数或汇总通信概率来计算聚合网络

cc.AD_pht <- netAnalysis_computeCentrality(cc.AD_pht, slot.name = "netP")#计算网络中心性得分，从而识别所有推断通信网络中的主要发送者、接收者、调解者和影响者

pathway.AD <- cc.AD_pht@netP$pathways
saveRDS(cc.AD_pht, "0_cc.AD_phenotype.rds")
cc.AD_pht <- readRDS('0_cc.AD_phenotype.rds')

