####___________naCTL####
#计算配受体分别在来源细胞和靶点细胞中表达情况

exp_naCTL <-  as.data.frame(scRNA_naCTL@assays$RNA@counts)
gc()

metadata_naCTL <- scRNA_naCTL@meta.data
metadata_naCTL$cells <- rownames(metadata_naCTL)

df.net_naCTL_pht$ligand_ratio <- 0
df.net_naCTL_pht$target_ratio <- 0

for (i in 1:nrow(df.net_naCTL_pht)){
  #提取配受体细胞的表达谱
  cell_ligand <- metadata_naCTL[which(metadata_naCTL$cluster == df.net_naCTL_pht[i,1]),"cells"]
  cell_target <- metadata_naCTL[which(metadata_naCTL$cluster == df.net_naCTL_pht[i,2]),"cells"]
  
  exp_ligand <- exp_naCTL[,cell_ligand]
  exp_target <- exp_naCTL[,cell_target]
 
  rate_ligand <- length(which(exp_ligand[df.net_naCTL_pht[i,3],] > 0))/length(cell_ligand)
  
  if(df.net_naCTL_pht[i,4] %in% rownames(exp_target)){
    rate_target <- length(which(exp_target[df.net_naCTL_pht[i,4],] > 0))/length(cell_target) 
  }else{
    target <- df.net_naCTL_pht[i,4]
    target_1 <- str_split(target,"_")[[1]][1]
    target_2 <- str_split(target,"_")[[1]][2]
    rate_target1 <- length(which(exp_target[target_1,] > 0))/length(cell_target) 
    rate_target2 <- length(which(exp_target[target_2,] > 0))/length(cell_target) 
    rate_target <-  (rate_target1 + rate_target2)/2
  }
  
  
  df.net_naCTL_pht[i,12] <- rate_ligand
  df.net_naCTL_pht[i,13] <- rate_target
  
  print(i)
}
write.table(df.net_naCTL_pht,"2_LR_naCTL_phenotype.txt",sep = "\t",col.names = T,row.names = F)


