#提取naCTL中的四个表型和AD中的6个表型合并
scRNA_naCTL_phenotype <- subset(scRNA,Group == "naCTL"  & cluster %in% phenotypes_na)

scRNA_AD_phenotype <- subset(scRNA,Group == "AD"  & cluster %in% phenotypes_ad)

scRNA_group_phenotype  <- merge(scRNA_naCTL_phenotype,scRNA_AD_phenotype, add.cell.ids = c('naCTL',"AD"), project = "group")


scRNA_group_phenotype$Group <- factor(scRNA_group_phenotype$Group,levels = c("naCTL","AD"))
scRNA_group_phenotype$cluster <- factor(scRNA_group_phenotype$cluster,levels = c(phenotypes_na,phenotypes_ad))
Idents(scRNA_group_phenotype) <- "cluster"


### 创建cellchat对象
cc.group_pht <- createCellChat(scRNA_group_phenotype@assays$RNA@data, meta = scRNA_group_phenotype@meta.data, group.by = "cluster")

cc.group_pht@DB <- CellChatDB.human
cc.group_pht <- subsetData(cc.group_pht)
cc.group_pht <- identifyOverExpressedGenes(cc.group_pht)#鉴定与每个细胞组相关的过表达信号基因
cc.group_pht <- identifyOverExpressedInteractions(cc.group_pht)#识别过表达的配体-受体相互作用
cc.group_pht <- projectData(cc.group_pht,PPI.human)#将基因表达数据投射到蛋白质-蛋白质相互作用网络上
cc.group_pht <- computeCommunProb(cc.group_pht, raw.use = TRUE, population.size = TRUE)#计算任何交互单元组之间的通信概率/强度
cc.group_pht <- computeCommunProbPathway(cc.group_pht)#通过汇总所有相关的配体/受体，计算信号通路水平上的通信概率
cc.group_pht <- aggregateNet(cc.group_pht)#通过计算链路数或汇总通信概率来计算聚合网络
cc.group_pht <- netAnalysis_computeCentrality(cc.group_pht, slot.name = "netP")#计算网络中心性得分，从而识别所有推断通信网络中的主要发送者、接收者、调解者和影响者
pathway.visgroup <- cc.group_pht@netP$pathways
saveRDS(cc.group_pht, "0_cc.vis_group_phenotype.rds")
cc.group_pht <- readRDS("0_cc.vis_group_phenotype.rds")


####_________提取LR与通路结果#######
#配受体对细胞通讯结果表：
df.net_group_pht <- subsetCommunication(cc.group_pht, slot.name = 'net')
write.table(df.net_group_pht,"4_LR_group_phenotype_all.txt",sep = "\t",col.names = T,row.names = F)

#信号通路水平细胞通讯结果表：
