####_________提取表型转换与分化相关的配受体对与通路####

#只提取与表型转换相关的配受体对
df.net_EC_pht <- df.net_group_pht[which(df.net_group_pht$source %in% c("APEC","AngEC") & df.net_group_pht$target %in% c("APEC","AngEC")),]
