df.net_Fib_pht <- df.net_group_pht[which(df.net_group_pht$source %in% c("QuieFib","InfFib","ConMyo") & df.net_group_pht$target %in% c("QuieFib","InfFib","ConMyo")),]
df.net_Macro_pht <- df.net_group_pht[which(df.net_group_pht$source %in% c("M2Macro","M1Macro") & df.net_group_pht$target %in% c("M2Macro","M1Macro")),]

#读取每个细胞类型中表型转换的分化特征基因
dir <- "D:\\1ISSUE\\主动脉夹层动脉瘤\\0_主动脉夹层测序数据\\自己\\3_subcluster"
EC_monocle_gene <- read.table(paste0(dir,"\\EC\\","7_highvariant_gene_monocle.txt"),sep = "\t",header = T,check.names = F,stringsAsFactors = F)
SMC_monocle_gene <- read.table(paste0(dir,"\\SMC\\","7_highvariant_gene_monocle.txt"),sep = "\t",header = T,check.names = F,stringsAsFactors = F)
Fib_monocle_gene <- read.table(paste0(dir,"\\Fib\\","7_highvariant_gene_monocle.txt"),sep = "\t",header = T,check.names = F,stringsAsFactors = F)
Macro_monocle_gene <- read.table(paste0(dir,"\\Macro\\","7_highvariant_gene_monocle.txt"),sep = "\t",header = T,check.names = F,stringsAsFactors = F)

#提取表型转换与分化相关的配受体对与通路
df.net_EC_pht_monocle <- df.net_EC_pht[which(df.net_EC_pht$ligand %in% EC_monocle_gene$gene_short_name | df.net_EC_pht$receptor %in% EC_monocle_gene$gene_short_name),]
