df.net_EC_pht_monocle$cell_type <- "EC"


df.net_SMC_pht_monocle <- df.net_SMC_pht[which(df.net_SMC_pht$ligand %in% SMC_monocle_gene$gene_short_name | df.net_SMC_pht$receptor %in% SMC_monocle_gene$gene_short_name),]
df.net_SMC_pht_monocle <- df.net_SMC_pht_monocle[which(df.net_SMC_pht_monocle$source != df.net_SMC_pht_monocle$target),]
df.net_SMC_pht_monocle <- df.net_SMC_pht_monocle[which(df.net_SMC_pht_monocle$source == "ConSMC" | df.net_SMC_pht_monocle$target == "ConSMC" ),]
df.net_SMC_pht_monocle$cell_type <- "SMC"

df.net_Fib_pht_monocle <- df.net_Fib_pht[which(df.net_Fib_pht$ligand %in% Fib_monocle_gene$gene_short_name | df.net_Fib_pht$target %in% Fib_monocle_gene$gene_short_name),]
df.net_Fib_pht_monocle <- df.net_Fib_pht_monocle[which(df.net_Fib_pht_monocle$source != df.net_Fib_pht_monocle$target),]
df.net_Fib_pht_monocle <- df.net_Fib_pht_monocle[which(df.net_Fib_pht_monocle$source == "QuieFib" | df.net_Fib_pht_monocle$target == "QuieFib" ),]
