df.net_Macro_pht_monocle <- df.net_Macro_pht_monocle[which(df.net_Macro_pht_monocle$source != df.net_Macro_pht_monocle$target),]
df.net_Macro_pht_monocle$cell_type <- "Macro"


df.net_group_pht_cell <- rbind(df.net_EC_pht_monocle,df.net_SMC_pht_monocle,df.net_Fib_pht_monocle,df.net_Macro_pht_monocle)


####___________计算配受体分别在来源细胞和靶点细胞中表达情况####

exp_naCTL <-  as.data.frame(scRNA_naCTL@assays$RNA@counts)
exp_AD <-  as.data.frame(scRNA_AD@assays$RNA@counts)

gc()

metadata_naCTL <- scRNA_naCTL@meta.data
metadata_naCTL$cells <- rownames(metadata_naCTL)
metadata_AD <- scRNA_AD@meta.data
metadata_AD$cells <- rownames(metadata_AD)


df.net_group_pht_cell$ligand_ratio <- 0
df.net_group_pht_cell$target_ratio <- 0

for (i in 1:nrow(df.net_group_pht_cell)){
  #提取配受体细胞的表达谱
  if(df.net_group_pht_cell[i,1] %in% phenotypes_na){
    cell_ligand <- metadata_naCTL[which(metadata_naCTL$cluster == df.net_group_pht_cell[i,1]),"cells"]
    exp_ligand <- exp_naCTL[,cell_ligand]
   
  }else{
    cell_ligand <- metadata_AD[which(metadata_AD$cluster == df.net_group_pht_cell[i,1]),"cells"]
    exp_ligand <- exp_AD[,cell_ligand]
  }
  
  if(df.net_group_pht_cell[i,2] %in% phenotypes_na){
    cell_target <- metadata_naCTL[which(metadata_naCTL$cluster == df.net_group_pht_cell[i,2]),"cells"]
    exp_target <- exp_naCTL[,cell_target]
    
  }else{
    cell_target <- metadata_AD[which(metadata_AD$cluster == df.net_group_pht_cell[i,2]),"cells"]
    exp_target <- exp_AD[,cell_target]
  }
  
  rate_ligand <- length(which(exp_ligand[df.net_group_pht_cell[i,3],] > 0))/length(cell_ligand)
  
  if(df.net_group_pht_cell[i,4] %in% rownames(exp_target)){
    rate_target <- length(which(exp_target[df.net_group_pht_cell[i,4],] > 0))/length(cell_target) 
  }else{
    target <- df.net_group_pht_cell[i,4]
    target_1 <- str_split(target,"_")[[1]][1]
    target_2 <- str_split(target,"_")[[1]][2]
    rate_target1 <- length(which(exp_target[target_1,] > 0))/length(cell_target) 
    rate_target2 <- length(which(exp_target[target_2,] > 0))/length(cell_target) 
    rate_target <-  (rate_target1 + rate_target2)/2
  }
  
  df.net_group_pht_cell[i,13] <- rate_ligand
  df.net_group_pht_cell[i,14] <- rate_target
  
  print(paste0("i = ",i,"  ",df.net_group_pht_cell[i,1],"_",df.net_group_pht_cell[i,2]))
}
write.table(df.net_group_pht_cell,"4_LR_group_phenotype_switching.txt",sep = "\t",col.names = T,row.names = F)


#筛选配受体基因分别表达大于0.5

df.net_group_pht_cell_sub <- df.net_group_pht_cell[which(df.net_group_pht_cell$ligand_ratio > 0.5 & df.net_group_pht_cell$target_ratio > 0.5),]


df.net_group_pht_cell_sub$cell_inter <- paste0(df.net_group_pht_cell_sub$source,"->",df.net_group_pht_cell_sub$target)


df.net_group_pht_cell_sub <- df.net_group_pht_cell_sub[order(df.net_group_pht_cell_sub$source,df.net_group_pht_cell_sub$target),]


